# Entities module: classes with cross-module types
from types import Status, Point

@abstract
class Entity:
    _id: int
    _name: str

    def __init__(self, id: int, name: str):
        self._id = id
        self._name = name

    @abstract
    def describe(self) -> str:
        ...

    def get_id(self) -> int:
        return self._id

    def get_name(self) -> str:
        return self._name

class User(Entity):
    email: str

    def __init__(self, id: int, name: str, email: str):
        super().__init__(id, name)
        self.email = email

    @override
    def describe(self) -> str:
        return f"User: {self._name} ({self.email})"

    def get_display_name(self) -> str:
        return f"@{self._name}"

class Task(Entity):
    _status: Status
    _location: Point

    def __init__(self, id: int, name: str, location: Point):
        super().__init__(id, name)
        self._status = Status.PENDING
        self._location = location

    @override
    def describe(self) -> str:
        return f"Task: {self._name} at ({self._location.x}, {self._location.y})"

    def get_status(self) -> Status:
        return self._status

    def set_status(self, status: Status) -> None:
        self._status = status

class Worker(User):
    _current_task: Task?
    _completed_count: int

    def __init__(self, id: int, name: str, email: str):
        super().__init__(id, name, email)
        self._current_task = None()
        self._completed_count = 0

    def get_status_enum(self) -> Status:
        if self._current_task is not None:
            return Status.ACTIVE
        return Status.COMPLETED

    def assign_task(self, task: Task) -> None:
        self._current_task = Some(task)
        task.set_status(Status.ACTIVE)

    def complete_task(self) -> None:
        if self._current_task is not None:
            task: Task = self._current_task.unwrap()
            task.set_status(Status.COMPLETED)
            self._completed_count = self._completed_count + 1
            self._current_task = None()

    def get_completed_count(self) -> int:
        return self._completed_count

