# Utils module: helper functions using types from types module
from types import Status, Point

def status_to_string(status: Status) -> str:
    if status == Status.PENDING:
        return "pending"
    elif status == Status.ACTIVE:
        return "active"
    elif status == Status.COMPLETED:
        return "completed"
    else:
        return "failed"

def format_point(p: Point) -> str:
    return f"({p.x}, {p.y})"

def distance_between(p1: Point, p2: Point) -> float:
    return p1.distance_from(p2)

def check_status_message(status: Status) -> str:
    return f"Status: {status_to_string(status)}"
